// 기간별 변경 빈도(freq)를 계산한다.
//  - day1  = now 기준 최근 24시간 내 변경 횟수
//  - day7  = now 기준 최근 7일 내 변경 횟수
//  - total = 전체 변경 횟수(churn_count 원천 — change_dates 절단과 무관하게 정확)
// change_dates 가 없거나(구 사이드카) 파싱 불가한 값은 조용히 무시(throw 금지).
function computeFreq(meta, now) {
  const rec = meta || {};
  const nowMs = now instanceof Date ? now.getTime() : Date.parse(now);
  const base = Number.isNaN(nowMs) ? Date.now() : nowMs;

  const dates = Array.isArray(rec.change_dates) ? rec.change_dates : [];
  let day1 = 0;
  let day7 = 0;
  for (const d of dates) {
    const t = Date.parse(d);
    if (Number.isNaN(t)) continue; // 깨진 값은 건너뛴다
    const idleMs = base - t;
    if (idleMs < 0) continue; // 미래 시각은 세지 않는다
    if (idleMs <= DAY_MS) day1 += 1;
    if (idleMs <= 7 * DAY_MS) day7 += 1;
  }

  // total 은 churn_count 를 원천으로 한다(전체 변경 횟수, 상한 절단 영향 없음).
  const total = Number.isFinite(rec.churn_count) ? rec.churn_count : dates.length;
  return { day1, day7, total };
}

