'use strict';
const path = require('path');
const PROJ = '/Users/won-yechan/miru_github/agent-dashboard';
const [gitRoot, mtimeRoot, oldRoot] = process.argv.slice(2);

let failures = 0;
function assert(name, cond, extra) {
  if (cond) {
    console.log('  PASS ' + name);
  } else {
    failures++;
    console.log('  FAIL ' + name + (extra ? '  -> ' + JSON.stringify(extra) : ''));
  }
}

function run(root, mode) {
  // 모듈 캐시를 지우고 canonical 오버라이드를 걸어 재로딩(paths가 env를 매 호출 읽으므로 사실 불필요하지만 안전).
  process.env.AAD_CANONICAL = root;
  delete process.env.AAD_NOW;
  for (const k of Object.keys(require.cache)) delete require.cache[k];
  const maintenance = require(path.join(PROJ, 'cli', 'maintenance.js'));
  const now = new Date(); // 실시간 now — 커밋 오프셋(10분/3일/20일)이 상대적이라 안정
  const out = maintenance.usage(now);
  return out;
}

console.log('== 1) git canonical: freq 정확도 (10분/3일/20일 전 커밋 3개) ==');
{
  const out = run(gitRoot, 'git');
  const item = out.items.find((x) => x.id === 'skill-demo');
  assert('item 존재', !!item);
  if (item) {
    assert('freq shape {day1,day7,total}',
      item.freq && typeof item.freq.day1 === 'number' && typeof item.freq.day7 === 'number' && typeof item.freq.total === 'number',
      item.freq);
    assert('day1 == 1 (10분 전 1개)', item.freq.day1 === 1, item.freq);
    assert('day7 == 2 (10분+3일)', item.freq.day7 === 2, item.freq);
    assert('total == 3 (전체)', item.freq.total === 3, item.freq);
    assert('telemetry.change_dates 길이 3', Array.isArray(item.telemetry.change_dates) && item.telemetry.change_dates.length === 3, item.telemetry.change_dates);
    assert('기존 필드 유지: telemetry/state/lastActivity 존재',
      !!item.telemetry && typeof item.state === 'string' && 'lastActivity' in item);
  }
}

console.log('== 2) mtime 폴백(비-git canonical): freq 형태 유지 ==');
{
  const out = run(mtimeRoot, 'mtime');
  const item = out.items.find((x) => x.id === 'skill-demo');
  assert('item 존재', !!item);
  if (item) {
    assert('freq shape 유지', item.freq && typeof item.freq.day1 === 'number' && typeof item.freq.day7 === 'number' && typeof item.freq.total === 'number', item.freq);
    // 방금 만든 파일 → mtime 이 지금 → day1/day7 각 1, total = churn_count(0)
    assert('day1 == 1 (방금 mtime)', item.freq.day1 === 1, item.freq);
    assert('day7 == 1', item.freq.day7 === 1, item.freq);
    assert('total == 0 (mtime은 churn 모름)', item.freq.total === 0, item.freq);
    assert('source == mtime', (item.telemetry.signal_sources || []).includes('mtime'), item.telemetry.signal_sources);
  }
}

console.log('== 3) 구 사이드카(change_dates 없음) 하위호환 ==');
{
  const out = run(oldRoot, 'old');
  const item = out.items.find((x) => x.id === 'skill-demo');
  assert('item 존재', !!item);
  if (item) {
    // recompute 가 돌면 git 이력으로 change_dates 를 다시 채운다(3일 전 1커밋).
    assert('freq shape 유지(throw 없이)', item.freq && typeof item.freq.day1 === 'number', item.freq);
    assert('day7 == 1 (3일 전 1커밋 재계산)', item.freq.day7 === 1, item.freq);
    assert('total == 1', item.freq.total === 1, item.freq);
    assert('change_dates 재생성됨(길이 1)', Array.isArray(item.telemetry.change_dates) && item.telemetry.change_dates.length === 1, item.telemetry.change_dates);
  }
}

console.log('');
if (failures === 0) { console.log('ALL PASS'); process.exit(0); }
else { console.log(failures + ' FAILURE(S)'); process.exit(1); }

